    const metrics = widthMap?.get(glyphId) ?? atlas.glyphs.get(glyphId);
    if (!metrics) {
      console.warn("metrics missing");
      return null;
    }
    const atlasW = atlas.bitmap.width;
    const atlasH = atlas.bitmap.rows;
