    fontState,
    defaultBg,
    buildFontAtlasIfNeeded: buildFontAtlasIfNeeded2,
    FONT_SCALE_OVERRIDES,
    isSymbolFont: isSymbolFont2,
    fontScaleOverride: fontScaleOverride2,
    getFontHinting,
    getFontHintTarget,
